  ('heelevel3-7fec267e-moex-00081', 'heelevel3-7fec267e', 'heelevel3-7fec267e-moex-113-3a7b2121', 'sub-heelevel3-7fec267e-03', NULL, 'single_choice', '政府為了充分顧及政治和社會多元價值，執行專業化、去政治化的公共事務而設置獨立機關，根 據我國法律規定，下列何者屬於「獨立機關」？', '["行政院公共工程委員會", "公平交易委員會", "國家發展委員會", "原住民族委員會"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:36+00:00", "source_pdf_sha1": "3c5fbab47917", "answer_pdf_sha1": "ea9f06b2527a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "301", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般行政"}'::jsonb, NULL),
